import React, { useEffect, useState } from "react";
import { getDebtDetails } from "../services/debtService";
import RepaymentPlan from "./repayment-plan";

export default function DebtDetails({ debtId }) {
  const [debt, setDebt] = useState(null);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    if (debtId) {
      loadDebtDetails();
    }
  }, [debtId]);

  async function loadDebtDetails() {
    try {
      const data = await getDebtDetails(debtId);
      setDebt(data);
    } catch (error) {
      console.error(error);
    }
  }

  if (!debtId) {
    return <p>Select a debt row to view details.</p>;
  }

  if (!debt) {
    return <p>Loading debt details...</p>;
  }

  return (
    <div className="container mt-4">

      {/* Header Card */}
      <div className="card shadow-sm mb-4">
        <div className="card-body">

          <div className="d-flex justify-content-between align-items-center">

            <div>
              <h3 className="mb-1">Debt Details</h3>
              <small className="text-muted">
                ID: {debt.id}
              </small>
            </div>

            <button
              className="btn btn-primary"
              onClick={() => setShowModal(true)}
            >
              + Add Payment Plan
            </button>

          </div>

        </div>
      </div>

      {/* Debt Info Card */}
      <div className="card shadow-sm mb-4">
        <div className="card-body">

          <h5 className="card-title">Summary</h5>

          <div className="row">

            <div className="col-md-4">
              <strong>Creditor</strong>
              <div>{debt.creditor}</div>
            </div>

            <div className="col-md-4">
              <strong>Current Balance</strong>
              <div>£{debt.currentBalance}</div>
            </div>

            <div className="col-md-4">
              <strong>Status</strong>
              <div>{debt.status}</div>
            </div>

          </div>

        </div>
      </div>

      {/* Payment Plans Placeholder (optional) */}
      <div className="card shadow-sm">
        <div className="card-body">
          <h5 className="card-title">Payment Plans</h5>

          <p className="text-muted mb-0">
            Add a repayment plan to get started.
          </p>

        </div>
      </div>

      <button className="btn btn-primary" onClick={() => setShowModal(true)}>
        {" "}
        Add Payment Plan
      </button>

      <RepaymentPlan
        show={showModal}
        debtId={debt.id}
        onClose={() => setShowModal(false)}
      />
    </div>
  );
}
